/*
Emitted when OpenXR recommends running a discovery query because entities managed by this spatial context have (likely) changed.
*/
func (self Instance) OnSpatialDiscoveryRecommended(cb func(spatial_context RID.Any), flags ...Signal.Flags) Instance {
	var flags_together Signal.Flags
	for _, flag := range flags {
		flags_together |= flag
	}
	gd.ObjectConnect(self.AsObject()[0], gd.NewStringName("spatial_discovery_recommended"), gd.NewCallable(cb), int64(flags_together))
	return self
}

func (self class) SpatialDiscoveryRecommended() Signal.Any {
	return Signal.Via(gd.SignalProxy{}, pointers.Pack(gd.NewSignalOf(self.AsObject(), gd.NewStringName(`spatial_discovery_recommended`))))
}

